const retreatX = args.targetX;
const retreatZ = args.targetZ;
const breadName = 'bread';

const hasBread = () => bot.inventory.items().some(item => item.name === breadName);
const horizontalDistance = (pos) => Math.hypot(pos.x - retreatX, pos.z - retreatZ);

const movements = new Movements(bot);
bot.pathfinder.setMovements(movements);
bot.pathfinder.setGoal(new goals.GoalXZ(retreatX, retreatZ));

let reached = false;

while (true) {
  const dist = horizontalDistance(bot.entity.position);
  reached = dist <= 2;

  const needsFood = bot.food < 20 && hasBread();

  if (reached && !needsFood) break;

  if (needsFood) {
    try {
      const breadItem = bot.inventory.items().find(item => item.name === breadName);
      if (breadItem) {
        await bot.equip(breadItem, 'hand');
        await bot.consume();
      }
    } catch (e) {
      // Eating interrupted, continue retreating
    }
  }

  if (!reached && !bot.pathfinder.goal) {
    bot.pathfinder.setGoal(new goals.GoalXZ(retreatX, retreatZ));
  }

  await new Promise(resolve => setTimeout(resolve, 100));
}

bot.pathfinder.setGoal(null);

if (reached) {
  if (bot.food >= 20) {
    return '<SUCCESS>: Retreated to destination and ate bread until full.';
  } else if (!hasBread()) {
    return '<PARTIAL>: Retreated to destination but ran out of bread.';
  } else {
    return '<SUCCESS>: Retreated to destination.';
  }
} else {
  return '<FAILED>: Did not reach the retreat coordinates.';
}
